    }

    // 创建并行任务列表
    List<UniTask> tasks = Readers.Select(reader =>
    {
        // 创建异步任务
        return UniTask.Create(async () =>
        {
            await reader.Value.Read(locations); // 异步执行读取操作
            // 注意: 现在我们不在这里更新进度了，因为Collection会负责它
        });
    }).ToList();

    // ...
}
```

请注意，在上述修改中，我们假设每个位置 `location` 包含的精灵数量相同。但是，如果它们有不同数量的精灵，那么您需要进一步的逻辑来在 `CollectAddressableResources` 方法中正确地计算 `TotalLoadCount`。

还需要注意，上面的代码假设了 `LoadAssetAsync<Sprite[]>()` 方法将对于每个 `location` 调用一次。如果你对每个 `sprite` 调用，那么 `TotalLoadCount` 的初始化方式也会不同。你需要知道每次加载操作将要添加多少个纹理来正确计算总量。

这样修改后的代码应该能够在每次添加新纹理时更新进度，并且可以通过 `IProgress<float>` 回调来通知调用者。请根据您项目的具体情况调整和测试代码。

出现此种情况可能是因为 `Stopwatch` 的计时存在误差，或者是因为异步任务的并行性导致计时不准确。在处理异步代码和 `UniTask` 时，`Stopwatch` 的计时可能不会精确反映真实的耗时，尤其是当异步任务被分派到不同的线程或任务调度器时。

首先要确认的是，`Stopwatch` 的 `Start()` 和 `Stop()` 方法是在正确的位置调用的，并且在所有相关的异步任务都真正完成之后调用 `Stop()`。例如，如果存在任何 `await` 操作在 `Stop()` 之后，`Stopwatch` 将不会在实际工作完成后立即停止。

以下是调整后的 `ReadAll` 方法，以确保 `Stopwatch` 正确计时：

```csharp
public static async Task ReadAll(IProgress<float> progressCallback = null)
{
    if (Readers.ToList().Any(reader => reader.Value.IsLoaded))
    {
        progressCallback?.Report(1.0f);
        return;
    }
    var stopwatch = new System.Diagnostics.Stopwatch();
    stopwatch.Start();

    var locations = await Addressables.LoadResourceLocationsAsync("Avatars").Task;

    var totalTasks = Readers.Count;
    var completedTasks = 0;

    // 创建并行任务列表
    List<UniTask> tasks = Readers.Select(reader =>
    {
        // 创建异步任务
        return UniTask.Create(async () =>
        {
            await reader.Value.Read(locations); // 异步执行读取操作
            // 省略进度回调...
        });
    }).ToList();

    // 在所有异步操作真正开始之后立即启动计时
    stopwatch.Start();

    // 等待所有任务完成
    await UniTask.WhenAll(tasks);

    // 确保所有异步操作完成之后立即停止计时
    stopwatch.Stop();

    Debug.Log("Read all textures in " + stopwatch.ElapsedMilliseconds + "ms");
}

```

注意，为了得到准确的耗时，调用 `stopwatch.Start()` 应该在派发所有异步任务后，并且调用 `stopwatch.Stop()` 应该在 `await UniTask.WhenAll(tasks)` 后面，确保所有实际的异步工作都完成了。

如果还有疑问，您可以考虑使用 `Time.realtimeSinceStartup` 来计算耗时。它返回从游戏开始到现在的时间（秒为单位），并且不会受到时间缩放的影响。这样您可以对比 `Stopwatch` 和 `Time.realtimeSinceStartup` 的结果，判断是否存在计时偏差。

```csharp
float startRealTime = Time.realtimeSinceStartup;

// ... 异步任务 ...

float elapsedRealTime = Time.realtimeSinceStartup - startRealTime;
Debug.Log("Read all textures in " + (elapsedRealTime * 1000f) + "ms");
```

在 Unity 中，这个方法通常更适合于在非编辑器代码中测量真实的时间间隔。
